fn patch_form_body_parameter(
    text: &mut String,
    parameter: &FormXmlParameter,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    for range in fields {
        if !text[range.clone()].trim_start().starts_with('{') {
            continue;
        }
        let mut nested = text[range.clone()].to_string();
        if patch_form_body_parameter_entry(&mut nested, parameter, source)? {
            text.replace_range(range, &nested);
            return Ok(true);
        }
    }
    Ok(false)
}

fn patch_form_body_parameter_entry(
    text: &mut String,
    parameter: &FormXmlParameter,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    let existing_name = fields
        .get(1)
        .and_then(|range| parse_1c_quoted_string(&text[range.clone()]).ok());
    if existing_name.as_deref() != Some(parameter.name.as_str()) {
        return Ok(false);
    }

    let mut replacements = Vec::<(Range<usize>, String)>::new();
    if let Some(name_range) = fields.get(1) {
        replacements.push((name_range.clone(), format_1c_string(&parameter.name)));
    }
    if !parameter.types.is_empty()
        && let Some(type_range) = fields.get(2)
    {
        let type_pattern = format_form_parameter_type_pattern(parameter, source)?;
        if !one_c_values_equal_ignoring_ws(&text[type_range.clone()], &type_pattern) {
            replacements.push((type_range.clone(), type_pattern));
        }
    }
    if let Some(key_parameter) = parameter.key_parameter
        && let Some(key_range) = fields.get(3)
    {
        replacements.push((
            key_range.clone(),
            if key_parameter { "1" } else { "0" }.to_string(),
        ));
    }

    replacements.sort_by_key(|(range, _)| range.start);
    for (range, replacement) in replacements.into_iter().rev() {
        text.replace_range(range, &replacement);
    }
    Ok(true)
}

fn append_form_body_parameter(
    text: &mut String,
    parameter: &FormXmlParameter,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some("0") {
        return Ok(false);
    }
    let Some(count_range) = fields.get(1).cloned() else {
        return Ok(false);
    };
    let Ok(count) = text[count_range.clone()].trim().parse::<usize>() else {
        return Ok(false);
    };
    if fields.len() != 2 + count {
        return Ok(false);
    }

    let entry = format_form_body_new_parameter(parameter, source)?;
    text.replace_range(count_range, &(count + 1).to_string());
    let insert_at = text
        .rfind('}')
        .ok_or_else(|| anyhow!("Form parameters section is not closed"))?;
    text.insert_str(insert_at, &format!(",{entry}"));
    Ok(true)
}

fn format_form_body_new_parameter(
    parameter: &FormXmlParameter,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    Ok(format!(
        "{{0,{},{},{}}}",
        format_1c_string(&parameter.name),
        format_form_parameter_type_pattern(parameter, source)?,
        if parameter.key_parameter == Some(true) {
            "1"
        } else {
            "0"
        }
    ))
}

fn format_form_parameter_type_pattern(
    parameter: &FormXmlParameter,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    let value_types = parse_metadata_type_pattern_elements(
        "Form Parameter",
        &parameter.types,
        parameter.string_length.clone(),
        parameter.string_allowed_length.clone(),
        parameter.number_digits.clone(),
        parameter.number_fraction_digits.clone(),
        parameter.number_allowed_sign.clone(),
        source,
        true,
    )?;
    Ok(format_metadata_type_pattern(&value_types))
}

fn patch_form_body_attributes(
    text: &mut String,
    attributes: &[FormXmlAttribute],
    source: Option<&MetadataSourceContext>,
) -> Result<()> {
    retain_form_body_attributes(text, attributes)?;
    for attribute in attributes {
        let patched = patch_form_body_attribute(text, attribute, source)?;
        if !patched {
            let _ = append_form_body_attribute(text, attribute, source)?;
        }
    }
    Ok(())
}

fn retain_form_body_attributes(text: &mut String, attributes: &[FormXmlAttribute]) -> Result<()> {
    let keep_ids = attributes
        .iter()
        .map(|attribute| attribute.id.as_str())
        .collect::<BTreeSet<_>>();
    let keep_names = attributes
        .iter()
        .map(|attribute| attribute.name.as_str())
        .collect::<BTreeSet<_>>();
    let fields = scan_braced_fields(text, 0)?;
    match fields.first().map(|range| text[range.clone()].trim()) {
        Some("0") => return Ok(()),
        Some("4") => {}
        _ => return Ok(()),
    }
    let Some(count_range) = fields.get(1) else {
        return Ok(());
    };
    let Ok(count) = text[count_range.clone()].trim().parse::<usize>() else {
        return Ok(());
    };
    if fields.len() != 2 + count {
        return Ok(());
    }

    let mut entries = Vec::new();
    for range in fields.iter().skip(2) {
        let entry = text[range.clone()].to_string();
        match form_body_attribute_entry_identity(&entry)? {
            Some((id, name))
                if keep_ids.contains(id.as_str())
                    || name
                        .as_deref()
                        .is_some_and(|name| keep_names.contains(name)) =>
            {
                entries.push(entry)
            }
            Some(_) => {}
            None => entries.push(entry),
        }
    }
    if entries.len() == count {
        return Ok(());
    }
    if entries.is_empty() {
        *text = "{0}".to_string();
        return Ok(());
    }

    let mut replacement = format!("{{4,{}", entries.len());
    for entry in entries {
        replacement.push(',');
        replacement.push_str(&entry);
    }
    replacement.push('}');
    *text = replacement;
    Ok(())
}

fn form_body_attribute_entry_identity(text: &str) -> Result<Option<(String, Option<String>)>> {
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some("9") {
        return Ok(None);
    }
    let Some(identity_range) = fields.get(1) else {
        return Ok(None);
    };
    let identity = scan_braced_fields(text, identity_range.start)?;
    let Some(id) = identity
        .first()
        .map(|range| text[range.clone()].trim().to_string())
        .filter(|id| !id.is_empty())
    else {
        return Ok(None);
    };
    let name = fields
        .get(3)
        .and_then(|range| parse_1c_quoted_string(&text[range.clone()]).ok());
    Ok(Some((id, name)))
}

fn patch_form_body_attribute(
    text: &mut String,
    attribute: &FormXmlAttribute,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    for range in fields {
        if !text[range.clone()].trim_start().starts_with('{') {
            continue;
        }
        let mut nested = text[range.clone()].to_string();
        if patch_form_body_attribute_entry(&mut nested, attribute, source)? {
            text.replace_range(range, &nested);
            return Ok(true);
        }
        if patch_form_body_attribute(&mut nested, attribute, source)? {
            text.replace_range(range, &nested);
            return Ok(true);
        }
    }
    Ok(false)
}

fn patch_form_body_attribute_entry(
    text: &mut String,
    attribute: &FormXmlAttribute,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some("9") {
        return Ok(false);
    }
    let existing_id = fields
        .get(1)
        .and_then(|range| scan_braced_fields(text, range.start).ok())
        .and_then(|identity| {
            identity
                .first()
                .map(|range| text[range.clone()].trim().to_string())
        });
    let existing_name = fields
        .get(3)
        .and_then(|range| parse_1c_quoted_string(&text[range.clone()]).ok());
    let matches_attribute = existing_id.as_deref() == Some(attribute.id.as_str())
        || existing_name.as_deref() == Some(attribute.name.as_str());
    if !matches_attribute {
        return Ok(false);
    }

    let mut replacements = Vec::<(Range<usize>, String)>::new();
    if let Some(name_range) = fields.get(3)
        && parse_1c_quoted_string(&text[name_range.clone()]).is_ok()
    {
        replacements.push((name_range.clone(), format_1c_string(&attribute.name)));
    }
    if let Some(main_attribute) = attribute.main_attribute
        && let Some(main_range) = fields.get(10)
    {
        replacements.push((
            main_range.clone(),
            if main_attribute { "1" } else { "0" }.to_string(),
        ));
    }
    if let Some(settings) = &attribute.settings
        && let Some(settings_range) = fields.get(14)
    {
        let mut settings_text = text[settings_range.clone()].to_string();
        patch_form_dynamic_list_settings(&mut settings_text, settings, source)?;
        replacements.push((settings_range.clone(), settings_text));
    }

    replacements.sort_by_key(|(range, _)| range.start);
    for (range, replacement) in replacements.into_iter().rev() {
        text.replace_range(range, &replacement);
    }
    Ok(true)
}

fn append_form_body_attribute(
    text: &mut String,
    attribute: &FormXmlAttribute,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    if attribute.types.is_empty() {
        return Ok(false);
    }
    let fields = scan_braced_fields(text, 0)?;
    match fields.first().map(|range| text[range.clone()].trim()) {
        Some("0") if fields.len() == 1 => {
            let entry = format_form_body_new_attribute(attribute, source)?;
            *text = format!("{{4,1,{entry}}}");
            Ok(true)
        }
        Some("4") => {
            let Some(count_range) = fields.get(1).cloned() else {
                return Ok(false);
            };
            let Ok(count) = text[count_range.clone()].trim().parse::<usize>() else {
                return Ok(false);
            };
            if fields.len() != 2 + count {
                return Ok(false);
            }
            let entry = format_form_body_new_attribute(attribute, source)?;
            text.replace_range(count_range, &(count + 1).to_string());
            let insert_at = text
                .rfind('}')
                .ok_or_else(|| anyhow!("Form attributes section is not closed"))?;
            text.insert_str(insert_at, &format!(",{entry}"));
            Ok(true)
        }
        _ => Ok(false),
    }
}

fn format_form_body_new_attribute(
    attribute: &FormXmlAttribute,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    let settings_text = if let Some(settings) = &attribute.settings {
        format_form_dynamic_list_settings_new(settings, source)?
    } else {
        "{0,0}".to_string()
    };
    Ok(format!(
        "{{9,{{{}}},0,{},{},{},{},{},{},{},{},0,0,0,{},{}}}",
        attribute.id,
        format_1c_string(&attribute.name),
        "{1,0}",
        format_form_attribute_type_pattern(attribute, source)?,
        r#"{0,{0,{"B",1},0}}"#,
        r#"{0,{0,{"B",1},0}}"#,
        "{0,0}",
        "{0,0}",
        if attribute.main_attribute == Some(true) {
            "1"
        } else {
            "0"
        },
        settings_text,
        "{0,0}"
    ))
}

fn format_form_attribute_type_pattern(
    attribute: &FormXmlAttribute,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    if attribute.types.len() == 1 && attribute.types[0].trim() == "cfg:DynamicList" {
        return Ok(format!(
            "{{\"Pattern\",{{\"#\",{}}}}}",
            FORM_DYNAMIC_LIST_TYPE_UUID
        ));
    }
    let value_types = parse_metadata_type_pattern_elements(
        "Form Attribute",
        &attribute.types,
        attribute.string_length.clone(),
        attribute.string_allowed_length.clone(),
        attribute.number_digits.clone(),
        attribute.number_fraction_digits.clone(),
        attribute.number_allowed_sign.clone(),
        source,
        true,
    )?;
    Ok(format_metadata_type_pattern(&value_types))
}

fn format_form_dynamic_list_settings_new(
    settings: &FormXmlDynamicListSettings,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    let mut pairs = Vec::<(&str, String)>::new();
    if let Some(query_text) = &settings.query_text {
        pairs.push(("QueryText", format_form_setting_string(query_text)));
    }
    if let Some(main_table) = &settings.main_table
        && let Some(source) = source
    {
        pairs.push((
            "MainTable",
            format_form_setting_metadata_ref(source, main_table)?,
        ));
    }
    if let Some(dynamic_data_read) = settings.dynamic_data_read {
        pairs.push((
            "DynamicalDataSelection",
            format_form_setting_bool(!dynamic_data_read),
        ));
    }
    if let Some(manual_query) = settings.manual_query {
        pairs.push(("ManualQuery", format_form_setting_bool(manual_query)));
    }
    if let Some(filter) = &settings.list_settings.filter {
        pairs.push((
            "Filter",
            format_form_setting_dcs_standard_section(filter, "Filter", "", "Filter")?,
        ));
    }
    if let Some(order) = &settings.list_settings.order {
        pairs.push(("Order", format_form_setting_dcs_order(order, "", "Order")?));
    }
    if let Some(conditional_appearance) = &settings.list_settings.conditional_appearance {
        pairs.push((
            "ConditionalAppearance",
            format_form_setting_dcs_standard_section(
                conditional_appearance,
                "ConditionalAppearance",
                "",
                "ConditionalAppearance",
            )?,
        ));
    }
    if let Some(items_view_mode) = &settings.list_settings.items_view_mode {
        pairs.push(("ItemsViewMode", format_form_setting_string(items_view_mode)));
    }
    if let Some(items_user_setting_id) = &settings.list_settings.items_user_setting_id {
        pairs.push((
            "ItemsUserSettingID",
            format_form_setting_string(items_user_setting_id),
        ));
    }

    let mut text = format!("{{0,{}", pairs.len());
    for (key, value) in pairs {
        text.push(',');
        text.push_str(&format_1c_string(key));
        text.push(',');
        text.push_str(&value);
    }
    text.push('}');
    Ok(text)
}

fn patch_form_dynamic_list_settings(
    text: &mut String,
    settings: &FormXmlDynamicListSettings,
    source: Option<&MetadataSourceContext>,
) -> Result<()> {
    if let Some(query_text) = &settings.query_text {
        let current_matches = find_form_setting_value_range(text, "QueryText")
            .is_some_and(|range| form_setting_string_matches(&text[range], query_text));
        if !current_matches {
            let _ = patch_form_setting_value(
                text,
                "QueryText",
                &format_form_setting_string(query_text),
            )?;
        }
    }
    if let Some(manual_query) = settings.manual_query {
        let _ =
            patch_form_setting_value(text, "ManualQuery", &format_form_setting_bool(manual_query))?;
    }
    if let Some(dynamic_data_read) = settings.dynamic_data_read {
        let data_selection = !dynamic_data_read;
        let _ = patch_form_setting_value(
            text,
            "DynamicalDataSelection",
            &format_form_setting_bool(data_selection),
        )?;
    }
    if let Some(main_table) = &settings.main_table
        && let Some(source) = source
    {
        let uuid = source.resolve_metadata_reference_uuid(main_table)?;
        let current_matches = find_form_setting_value_range(text, "MainTable")
            .is_some_and(|range| form_setting_metadata_ref_contains_uuid(&text[range], &uuid));
        if !current_matches {
            let _ = patch_form_setting_value(text, "MainTable", &format!("{{\"#\",{uuid}}}"))?;
        }
    }
    let mut list_replacements = Vec::new();
    let list_settings_text = text.clone();
    if let Some(order) = &settings.list_settings.order {
        push_form_setting_dcs_order_replacement(
            &list_settings_text,
            "Order",
            order,
            &mut list_replacements,
        )?;
    }
    if let Some(conditional_appearance) = &settings.list_settings.conditional_appearance {
        push_form_setting_dcs_standard_replacement(
            &list_settings_text,
            "ConditionalAppearance",
            conditional_appearance,
            "ConditionalAppearance",
            &mut list_replacements,
        )?;
    }
    if let Some(items_view_mode) = &settings.list_settings.items_view_mode {
        push_form_setting_replacement(
            &list_settings_text,
            "ItemsViewMode",
            format_form_setting_string(items_view_mode),
            &mut list_replacements,
        )?;
    }
    if let Some(items_user_setting_id) = &settings.list_settings.items_user_setting_id {
        push_form_setting_replacement(
            &list_settings_text,
            "ItemsUserSettingID",
            format_form_setting_string(items_user_setting_id),
            &mut list_replacements,
        )?;
    }
    if let Some(filter) = &settings.list_settings.filter {
        push_form_setting_dcs_standard_replacement(
            &list_settings_text,
            "Filter",
            filter,
            "Filter",
            &mut list_replacements,
        )?;
    }
    list_replacements.sort_by_key(|(range, _)| range.start);
    for (range, replacement) in list_replacements.into_iter().rev() {
        text.replace_range(range, &replacement);
    }
    Ok(())
}

fn patch_form_setting_value(text: &mut String, key: &str, replacement: &str) -> Result<bool> {
    if let Some(range) = find_form_setting_value_range(text, key) {
        text.replace_range(range, replacement);
        return Ok(true);
    }
    let fields = scan_braced_fields(text, 0)?;
    for window in fields.windows(2) {
        let Ok(existing_key) = parse_1c_quoted_string(&text[window[0].clone()]) else {
            continue;
        };
        if existing_key == key {
            text.replace_range(window[1].clone(), replacement);
            return Ok(true);
        }
    }
    Ok(false)
}

fn form_setting_metadata_ref_contains_uuid(value: &str, uuid: &str) -> bool {
    let value = value.trim();
    let Ok(fields) = scan_braced_fields(value, 0) else {
        return false;
    };
    fields
        .first()
        .is_some_and(|range| value[range.clone()].trim() == "\"#\"")
        && fields
            .iter()
            .skip(1)
            .any(|range| value[range.clone()].trim().eq_ignore_ascii_case(uuid))
}

fn form_setting_string_matches(existing: &str, expected: &str) -> bool {
    let existing = existing.trim();
    let Ok(fields) = scan_braced_fields(existing, 0) else {
        return false;
    };
    let text = existing.trim();
    if fields.first().map(|range| text[range.clone()].trim()) != Some(r#""S""#) {
        return false;
    }
    let Some(value) = fields
        .get(1)
        .and_then(|range| parse_1c_quoted_string(&text[range.clone()]).ok())
    else {
        return false;
    };
    normalize_newlines(&value) == normalize_newlines(expected)
}

fn normalize_newlines(value: &str) -> String {
    value.replace("\r\n", "\n").replace('\r', "\n")
}

fn push_form_setting_replacement(
    text: &str,
    key: &str,
    replacement: String,
    replacements: &mut Vec<(Range<usize>, String)>,
) -> Result<()> {
    if let Some(range) = find_form_setting_value_range(text, key) {
        replacements.push((range, replacement));
        return Ok(());
    }
    let fields = scan_braced_fields(text, 0)?;
    for window in fields.windows(2) {
        let Ok(existing_key) = parse_1c_quoted_string(&text[window[0].clone()]) else {
            continue;
        };
        if existing_key == key {
            replacements.push((window[1].clone(), replacement));
            return Ok(());
        }
    }
    Ok(())
}

fn push_form_setting_dcs_standard_replacement(
    text: &str,
    key: &str,
    section: &FormXmlListSettingsStandardSection,
    root_name: &str,
    replacements: &mut Vec<(Range<usize>, String)>,
) -> Result<()> {
    if let Some(range) = find_form_setting_value_range(text, key)
        && form_existing_dcs_standard_section_matches(&text[range.clone()], section)?
    {
        return Ok(());
    }
    push_form_setting_replacement(
        text,
        key,
        format_form_setting_dcs_standard_section(section, root_name, text, key)?,
        replacements,
    )
}

fn push_form_setting_dcs_order_replacement(
    text: &str,
    key: &str,
    order: &FormXmlListSettingsOrder,
    replacements: &mut Vec<(Range<usize>, String)>,
) -> Result<()> {
    if let Some(range) = find_form_setting_value_range(text, key)
        && form_existing_dcs_order_matches(&text[range.clone()], order)?
    {
        return Ok(());
    }
    push_form_setting_replacement(
        text,
        key,
        format_form_setting_dcs_order(order, text, key)?,
        replacements,
    )
}

fn form_existing_dcs_order_matches(
    existing: &str,
    order: &FormXmlListSettingsOrder,
) -> Result<bool> {
    let Some(xml) = form_setting_base64_xml(existing)? else {
        return Ok(false);
    };
    let parsed = parse_form_dcs_order_xml(&xml)?;
    if parsed.items.len() != order.items.len() {
        return Ok(false);
    }
    let items_match = order
        .items
        .iter()
        .zip(parsed.items.iter())
        .all(|(expected, actual)| {
            expected
                .field
                .as_deref()
                .is_none_or(|field| actual.field.as_deref() == Some(field))
                && expected
                    .order_type
                    .as_deref()
                    .is_none_or(|order_type| actual.order_type.as_deref() == Some(order_type))
        });
    let view_mode_matches = order
        .view_mode
        .as_deref()
        .is_none_or(|expected| parsed.view_mode.as_deref() == Some(expected));
    let user_setting_matches = order
        .user_setting_id
        .as_deref()
        .is_none_or(|expected| parsed.user_setting_id.as_deref() == Some(expected));
    Ok(items_match && view_mode_matches && user_setting_matches)
}

fn form_existing_dcs_standard_section_matches(
    existing: &str,
    section: &FormXmlListSettingsStandardSection,
) -> Result<bool> {
    let Some(xml) = form_setting_base64_xml(existing)? else {
        return Ok(false);
    };
    let parsed = parse_form_dcs_standard_section_xml(&xml)?;
    let view_mode_matches = section
        .view_mode
        .as_deref()
        .is_none_or(|expected| parsed.view_mode.as_deref() == Some(expected));
    let user_setting_matches = section
        .user_setting_id
        .as_deref()
        .is_none_or(|expected| parsed.user_setting_id.as_deref() == Some(expected));
    let items_match = if section.items.is_empty() {
        true
    } else {
        parsed.items.len() == section.items.len()
            && section
                .items
                .iter()
                .zip(parsed.items.iter())
                .all(|(expected, actual)| {
                    expected
                        .field
                        .as_deref()
                        .is_none_or(|field| actual.field.as_deref() == Some(field))
                })
    };
    Ok(items_match && view_mode_matches && user_setting_matches)
}

fn form_setting_base64_xml(existing: &str) -> Result<Option<String>> {
    let text = existing.trim();
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some(r##""#""##) {
        return Ok(None);
    }
    for range in fields.iter().skip(1) {
        let value = text[range.clone()].trim();
        if !value.starts_with("{#base64:") {
            continue;
        }
        let bytes = decode_base64_payload_field(value)?;
        let xml = String::from_utf8(bytes)
            .context("Form DCS setting base64 payload is not valid UTF-8")?;
        return Ok(Some(xml.trim_start_matches('\u{feff}').to_string()));
    }
    Ok(None)
}

#[derive(Default)]
struct ParsedFormDcsStandardSection {
    items: Vec<ParsedFormDcsFieldItem>,
    view_mode: Option<String>,
    user_setting_id: Option<String>,
}

#[derive(Default)]
struct ParsedFormDcsOrder {
    items: Vec<ParsedFormDcsOrderItem>,
    view_mode: Option<String>,
    user_setting_id: Option<String>,
}

#[derive(Default)]
struct ParsedFormDcsOrderItem {
    field: Option<String>,
    order_type: Option<String>,
}

#[derive(Default)]
struct ParsedFormDcsFieldItem {
    field: Option<String>,
}

fn parse_form_dcs_order_xml(xml: &str) -> Result<ParsedFormDcsOrder> {
    let mut reader = Reader::from_reader(xml.as_bytes());
    let mut buffer = Vec::new();
    let mut current = None::<String>;
    let mut text = String::new();
    let mut parsed = ParsedFormDcsOrder::default();
    let mut current_item = None::<ParsedFormDcsOrderItem>;
    loop {
        match reader.read_event_into(&mut buffer) {
            Ok(Event::Start(event)) => {
                let local = xml_local_name(event.local_name().as_ref());
                if local == "item" {
                    current_item = Some(ParsedFormDcsOrderItem::default());
                } else if matches!(
                    local.as_str(),
                    "field" | "orderType" | "viewMode" | "userSettingID"
                ) {
                    current = Some(local);
                    text.clear();
                }
            }
            Ok(Event::Text(event)) => {
                if current.is_some() {
                    text.push_str(event.xml_content()?.as_ref());
                }
            }
            Ok(Event::CData(event)) => {
                if current.is_some() {
                    text.push_str(event.xml_content()?.as_ref());
                }
            }
            Ok(Event::GeneralRef(reference)) => {
                if current.is_some() {
                    let value = if let Some(ch) = reference.resolve_char_ref()? {
                        ch.to_string()
                    } else {
                        let entity = reference.decode()?;
                        resolve_xml_entity(entity.as_ref())
                            .ok_or_else(|| anyhow!("unrecognized XML entity: {entity}"))?
                            .to_string()
                    };
                    text.push_str(&value);
                }
            }
            Ok(Event::End(event)) => {
                let local = xml_local_name(event.local_name().as_ref());
                if current.as_deref() == Some(local.as_str()) {
                    match local.as_str() {
                        "field" => {
                            if let Some(item) = current_item.as_mut() {
                                item.field = Some(text.trim().to_string());
                            }
                        }
                        "orderType" => {
                            if let Some(item) = current_item.as_mut() {
                                item.order_type = Some(text.trim().to_string());
                            }
                        }
                        "viewMode" => parsed.view_mode = Some(text.trim().to_string()),
                        "userSettingID" => parsed.user_setting_id = Some(text.trim().to_string()),
                        _ => {}
                    }
                    current = None;
                    text.clear();
                }
                if local == "item"
                    && let Some(item) = current_item.take()
                {
                    parsed.items.push(item);
                }
            }
            Ok(Event::Eof) => break,
            Err(error) => return Err(error.into()),
            _ => {}
        }
        buffer.clear();
    }
    Ok(parsed)
}

fn parse_form_dcs_standard_section_xml(xml: &str) -> Result<ParsedFormDcsStandardSection> {
    let mut reader = Reader::from_reader(xml.as_bytes());
    let mut buffer = Vec::new();
    let mut current = None::<String>;
    let mut text = String::new();
    let mut parsed = ParsedFormDcsStandardSection::default();
    let mut current_item = None::<ParsedFormDcsFieldItem>;
    loop {
        match reader.read_event_into(&mut buffer) {
            Ok(Event::Start(event)) => {
                let local = xml_local_name(event.local_name().as_ref());
                if local == "item" {
                    current_item = Some(ParsedFormDcsFieldItem::default());
                } else if matches!(local.as_str(), "field" | "viewMode" | "userSettingID") {
                    current = Some(local);
                    text.clear();
                }
            }
            Ok(Event::Text(event)) => {
                if current.is_some() {
                    text.push_str(event.xml_content()?.as_ref());
                }
            }
            Ok(Event::CData(event)) => {
                if current.is_some() {
                    text.push_str(event.xml_content()?.as_ref());
                }
            }
            Ok(Event::GeneralRef(reference)) => {
                if current.is_some() {
                    let value = if let Some(ch) = reference.resolve_char_ref()? {
                        ch.to_string()
                    } else {
                        let entity = reference.decode()?;
                        resolve_xml_entity(entity.as_ref())
                            .ok_or_else(|| anyhow!("unrecognized XML entity: {entity}"))?
                            .to_string()
                    };
                    text.push_str(&value);
                }
            }
            Ok(Event::End(event)) => {
                let local = xml_local_name(event.local_name().as_ref());
                if current.as_deref() == Some(local.as_str()) {
                    match local.as_str() {
                        "field" => {
                            if let Some(item) = current_item.as_mut() {
                                item.field = Some(text.trim().to_string());
                            }
                        }
                        "viewMode" => parsed.view_mode = Some(text.trim().to_string()),
                        "userSettingID" => parsed.user_setting_id = Some(text.trim().to_string()),
                        _ => {}
                    }
                    current = None;
                    text.clear();
                }
                if local == "item"
                    && let Some(item) = current_item.take()
                    && item.field.as_deref().is_some_and(|field| !field.is_empty())
                {
                    parsed.items.push(item);
                }
            }
            Ok(Event::Eof) => break,
            Err(error) => return Err(error.into()),
            _ => {}
        }
        buffer.clear();
    }
    Ok(parsed)
}

fn find_form_setting_value_range(text: &str, key: &str) -> Option<Range<usize>> {
    let needle = format!("\"{}\"", key.replace('"', "\"\""));
    let mut offset = 0usize;
    while let Some(relative) = text[offset..].find(&needle) {
        let key_start = offset + relative;
        let mut index = key_start + needle.len();
        while text
            .as_bytes()
            .get(index)
            .is_some_and(u8::is_ascii_whitespace)
        {
            index += 1;
        }
        if text.as_bytes().get(index) != Some(&b',') {
            offset = key_start + needle.len();
            continue;
        }
        index += 1;
        while text
            .as_bytes()
            .get(index)
            .is_some_and(u8::is_ascii_whitespace)
        {
            index += 1;
        }
        if let Some(range) = scan_1c_value_range(text, index) {
            return Some(range);
        }
        offset = key_start + needle.len();
    }
    None
}

fn scan_1c_value_range(text: &str, start: usize) -> Option<Range<usize>> {
    match text.as_bytes().get(start).copied()? {
        b'{' => scan_1c_braced_value_range(text, start),
        b'"' => scan_1c_quoted_value_range(text, start),
        _ => {
            let end = text[start..]
                .find([',', '}'])
                .map(|relative| start + relative)
                .unwrap_or(text.len());
            Some(trim_ascii_ws_range(text, start..end))
        }
    }
}

fn scan_1c_braced_value_range(text: &str, start: usize) -> Option<Range<usize>> {
    let bytes = text.as_bytes();
    let mut depth = 0usize;
    let mut in_string = false;
    let mut index = start;
    while index < bytes.len() {
        match bytes[index] {
            b'"' if in_string && bytes.get(index + 1) == Some(&b'"') => {
                index += 2;
                continue;
            }
            b'"' => in_string = !in_string,
            b'{' if !in_string => depth += 1,
            b'}' if !in_string => {
                depth = depth.checked_sub(1)?;
                if depth == 0 {
                    return Some(start..index + 1);
                }
            }
            _ => {}
        }
        index += 1;
    }
    None
}

fn scan_1c_quoted_value_range(text: &str, start: usize) -> Option<Range<usize>> {
    let bytes = text.as_bytes();
    let mut index = start + 1;
    while index < bytes.len() {
        if bytes[index] == b'"' {
            if bytes.get(index + 1) == Some(&b'"') {
                index += 2;
                continue;
            }
            return Some(start..index + 1);
        }
        index += 1;
    }
    None
}

fn format_form_setting_string(value: &str) -> String {
    format!("{{\"S\",{}}}", format_1c_string(value))
}

fn format_form_setting_bool(value: bool) -> String {
    format!("{{\"B\",{}}}", if value { "1" } else { "0" })
}

fn format_form_setting_metadata_ref(
    source: &MetadataSourceContext,
    reference: &str,
) -> Result<String> {
    let uuid = source.resolve_metadata_reference_uuid(reference)?;
    Ok(format!("{{\"#\",{uuid}}}"))
}

fn format_form_setting_dcs_order(
    order: &FormXmlListSettingsOrder,
    settings_text: &str,
    key: &str,
) -> Result<String> {
    let existing_uuid = find_form_setting_ref_uuid(settings_text, key)
        .unwrap_or_else(|| default_form_setting_ref_uuid(key).to_string());
    let xml = format_form_dcs_order_xml(order);
    let mut bytes = b"\xEF\xBB\xBF".to_vec();
    bytes.extend_from_slice(xml.as_bytes());
    Ok(format!(
        "{{\"#\",{existing_uuid},{{#base64:{}}}}}",
        encode_base64(&bytes)
    ))
}

fn format_form_setting_dcs_standard_section(
    section: &FormXmlListSettingsStandardSection,
    root_name: &str,
    settings_text: &str,
    key: &str,
) -> Result<String> {
    let existing_uuid = find_form_setting_ref_uuid(settings_text, key)
        .unwrap_or_else(|| default_form_setting_ref_uuid(key).to_string());
    let existing_xml = find_form_setting_value_range(settings_text, key).and_then(|range| {
        form_setting_base64_xml(&settings_text[range])
            .ok()
            .flatten()
    });
    let xml = format_form_dcs_standard_section_xml(section, root_name, existing_xml.as_deref())?;
    let mut bytes = b"\xEF\xBB\xBF".to_vec();
    bytes.extend_from_slice(xml.as_bytes());
    Ok(format!(
        "{{\"#\",{existing_uuid},{{#base64:{}}}}}",
        encode_base64(&bytes)
    ))
}

fn default_form_setting_ref_uuid(key: &str) -> &'static str {
    match key {
        "Filter" => "21743ff3-2db3-4cfc-9404-90ed8209437f",
        "ConditionalAppearance" => "31743ff3-2db3-4cfc-9404-90ed8209437f",
        _ => "11743ff3-2db3-4cfc-9404-90ed8209437f",
    }
}

fn find_form_setting_ref_uuid(text: &str, key: &str) -> Option<String> {
    let fields = scan_braced_fields(text, 0).ok()?;
    for window in fields.windows(2) {
        let Ok(existing_key) = parse_1c_quoted_string(&text[window[0].clone()]) else {
            continue;
        };
        if existing_key != key {
            continue;
        }
        let value_fields = scan_braced_fields(text, window[1].start).ok()?;
        if value_fields.first().map(|range| text[range.clone()].trim()) != Some(r##""#""##) {
            return None;
        }
        return value_fields
            .iter()
            .skip(1)
            .find_map(|range| parse_non_zero_uuid(text[range.clone()].trim()));
    }
    None
}

fn parse_non_zero_uuid(value: &str) -> Option<String> {
    let uuid = Uuid::parse_str(value.trim()).ok()?;
    (uuid != Uuid::nil()).then(|| uuid.hyphenated().to_string())
}

fn format_form_dcs_order_xml(order: &FormXmlListSettingsOrder) -> String {
    let mut xml = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n\
<Order xmlns=\"http://v8.1c.ru/8.1/data-composition-system/settings\" xmlns:xs=\"http://www.w3.org/2001/XMLSchema\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">\r\n"
        .to_string();
    for item in &order.items {
        let Some(field) = item.field.as_deref().filter(|field| !field.is_empty()) else {
            continue;
        };
        xml.push_str("\t<item xsi:type=\"OrderItemField\">\r\n");
        xml.push_str(&format!(
            "\t\t<field>{}</field>\r\n",
            escape_xml_text(field)
        ));
        if let Some(order_type) = item.order_type.as_deref().filter(|value| !value.is_empty()) {
            xml.push_str(&format!(
                "\t\t<orderType>{}</orderType>\r\n",
                escape_xml_text(order_type)
            ));
        }
        xml.push_str("\t</item>\r\n");
    }
    if let Some(view_mode) = order.view_mode.as_deref().filter(|value| !value.is_empty()) {
        xml.push_str(&format!(
            "\t<viewMode>{}</viewMode>\r\n",
            escape_xml_text(view_mode)
        ));
    }
    if let Some(user_setting_id) = order
        .user_setting_id
        .as_deref()
        .filter(|value| !value.is_empty())
    {
        xml.push_str(&format!(
            "\t<userSettingID>{}</userSettingID>\r\n",
            escape_xml_text(user_setting_id)
        ));
    }
    xml.push_str("</Order>");
    xml
}

fn format_form_dcs_standard_section_xml(
    section: &FormXmlListSettingsStandardSection,
    root_name: &str,
    existing_xml: Option<&str>,
) -> Result<String> {
    let mut xml = format!(
        "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n\
<{root_name} xmlns=\"http://v8.1c.ru/8.1/data-composition-system/settings\" xmlns:xs=\"http://www.w3.org/2001/XMLSchema\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\">\r\n"
    );
    for item in &section.items {
        let Some(field) = item.field.as_deref().filter(|field| !field.is_empty()) else {
            continue;
        };
        xml.push_str("\t<item xsi:type=\"FieldItem\">\r\n");
        xml.push_str(&format!(
            "\t\t<field>{}</field>\r\n",
            escape_xml_text(field)
        ));
        xml.push_str("\t</item>\r\n");
    }
    if let Some(existing_xml) = existing_xml {
        let replacement_fields = section
            .items
            .iter()
            .filter_map(|item| item.field.as_deref())
            .collect::<BTreeSet<_>>();
        for block in form_dcs_direct_item_blocks(existing_xml)? {
            if block
                .field
                .as_deref()
                .is_some_and(|field| replacement_fields.contains(field))
            {
                continue;
            }
            xml.push('\t');
            xml.push_str(block.xml.trim());
            xml.push_str("\r\n");
        }
    }
    if let Some(view_mode) = section
        .view_mode
        .as_deref()
        .filter(|value| !value.is_empty())
    {
        xml.push_str(&format!(
            "\t<viewMode>{}</viewMode>\r\n",
            escape_xml_text(view_mode)
        ));
    }
    if let Some(user_setting_id) = section
        .user_setting_id
        .as_deref()
        .filter(|value| !value.is_empty())
    {
        xml.push_str(&format!(
            "\t<userSettingID>{}</userSettingID>\r\n",
            escape_xml_text(user_setting_id)
        ));
    }
    xml.push_str(&format!("</{root_name}>"));
    Ok(xml)
}

struct FormDcsDirectItemBlock {
    xml: String,
    field: Option<String>,
}

fn form_dcs_direct_item_blocks(xml: &str) -> Result<Vec<FormDcsDirectItemBlock>> {
    let mut blocks = Vec::new();
    let mut depth = 0usize;
    let mut offset = 0usize;
    let mut current_start = None::<usize>;
    while let Some(relative_start) = xml[offset..].find('<') {
        let start = offset + relative_start;
        let Some(relative_end) = xml[start..].find('>') else {
            break;
        };
        let end = start + relative_end + 1;
        let tag = &xml[start + 1..end - 1];
        let tag = tag.trim();
        if tag.starts_with('?') || tag.starts_with('!') {
            offset = end;
            continue;
        }
        let closing = tag.starts_with('/');
        let empty = tag.ends_with('/');
        let name = tag
            .trim_start_matches('/')
            .trim_end_matches('/')
            .split_ascii_whitespace()
            .next()
            .unwrap_or_default();
        let local = name.rsplit(':').next().unwrap_or(name);
        if closing {
            if local == "item"
                && depth == 2
                && let Some(block_start) = current_start.take()
            {
                let block_xml = xml[block_start..end].to_string();
                blocks.push(FormDcsDirectItemBlock {
                    field: parse_form_dcs_direct_item_field(&block_xml)?,
                    xml: block_xml,
                });
            }
            depth = depth.saturating_sub(1);
        } else {
            if local == "item" && depth == 1 {
                current_start = Some(start);
            }
            if !empty {
                depth += 1;
            } else if local == "item" && depth == 1 {
                current_start = None;
                blocks.push(FormDcsDirectItemBlock {
                    field: None,
                    xml: xml[start..end].to_string(),
                });
            }
        }
        offset = end;
    }
    Ok(blocks)
}

fn parse_form_dcs_direct_item_field(xml: &str) -> Result<Option<String>> {
    let wrapper = format!("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\r\n<Items>{xml}</Items>");
    Ok(parse_form_dcs_standard_section_xml(&wrapper)?
        .items
        .into_iter()
        .find_map(|item| item.field))
}

fn escape_xml_text(value: &str) -> String {
    let mut output = String::with_capacity(value.len());
    for ch in value.chars() {
        match ch {
            '&' => output.push_str("&amp;"),
            '<' => output.push_str("&lt;"),
            '>' => output.push_str("&gt;"),
            '"' => output.push_str("&quot;"),
            _ => output.push(ch),
        }
    }
    output
}

fn patch_form_body_command(
    text: &mut String,
    command: &FormXmlCommand,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    for range in fields {
        if !text[range.clone()].trim_start().starts_with('{') {
            continue;
        }
        let mut nested = text[range.clone()].to_string();
        if patch_form_body_command_entry(&mut nested, command, source)? {
            text.replace_range(range, &nested);
            return Ok(true);
        }
        if patch_form_body_command(&mut nested, command, source)? {
            text.replace_range(range, &nested);
            return Ok(true);
        }
    }
    Ok(false)
}

fn patch_form_body_command_entry(
    text: &mut String,
    command: &FormXmlCommand,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some("11") {
        return Ok(false);
    }
    let existing_id = fields
        .get(1)
        .and_then(|range| scan_braced_fields(text, range.start).ok())
        .and_then(|identity| {
            identity
                .first()
                .map(|range| text[range.clone()].trim().to_string())
        });
    let existing_name = fields
        .get(2)
        .and_then(|range| parse_1c_quoted_string(&text[range.clone()]).ok());
    let matches_command = existing_id.as_deref() == Some(command.id.as_str())
        || existing_name.as_deref() == Some(command.name.as_str());
    if !matches_command {
        return Ok(false);
    }

    let mut replacements = Vec::<(Range<usize>, String)>::new();

    if let Some(name_range) = fields.get(2)
        && parse_1c_quoted_string(&text[name_range.clone()]).is_ok()
    {
        replacements.push((name_range.clone(), format_1c_string(&command.name)));
    }
    if !command.title.is_empty()
        && let Some(title_range) = fields.get(3)
        && let Some(replacement) =
            form_command_localized_replacement(&text[title_range.clone()], &command.title)
    {
        replacements.push((title_range.clone(), replacement));
    }
    if !command.tooltip.is_empty()
        && let Some(tooltip_range) = fields.get(4)
        && let Some(replacement) =
            form_command_localized_replacement(&text[tooltip_range.clone()], &command.tooltip)
    {
        replacements.push((tooltip_range.clone(), replacement));
    }
    if let Some(action) = &command.action
        && let Some(action_range) = fields.get(8)
        && parse_1c_quoted_string(&text[action_range.clone()]).is_ok()
    {
        replacements.push((action_range.clone(), format_1c_string(action)));
    }
    if let Some(current_row_use) = command.current_row_use
        && let Some(current_row_use_range) = fields.get(9)
    {
        replacements.push((
            current_row_use_range.clone(),
            form_command_current_row_use_code(current_row_use).to_string(),
        ));
    }
    if let Some(modifies_saved_data) = command.modifies_saved_data
        && let Some(modifies_saved_data_range) = fields.get(10)
    {
        replacements.push((
            modifies_saved_data_range.clone(),
            if modifies_saved_data { "1" } else { "0" }.to_string(),
        ));
    }
    if !command.functional_options.is_empty()
        && let Some(functional_options_range) = fields.get(12)
        && let Some(source) = source
    {
        replacements.push((
            functional_options_range.clone(),
            format_form_reference_list(source, &command.functional_options)?,
        ));
    }

    replacements.sort_by_key(|(range, _)| range.start);
    for (range, replacement) in replacements.into_iter().rev() {
        text.replace_range(range, &replacement);
    }

    Ok(true)
}

fn form_command_localized_replacement(
    existing: &str,
    values: &[LocalizedString],
) -> Option<String> {
    form_localized_replacement(existing, values)
}

fn form_localized_replacement(existing: &str, values: &[LocalizedString]) -> Option<String> {
    if parse_1c_localized_strings(existing).ok().as_deref() == Some(values) {
        return None;
    }
    Some(if form_localized_uses_nested_pairs(existing) {
        format_form_title_value(values)
    } else {
        format_1c_synonyms(values)
    })
}

fn form_localized_uses_nested_pairs(value: &str) -> bool {
    let value = value.trim();
    let Ok(fields) = scan_braced_fields(value, 0) else {
        return false;
    };
    fields
        .first()
        .is_some_and(|range| value[range.clone()].trim() == "1")
        && fields
            .get(1)
            .is_some_and(|range| value[range.clone()].trim().parse::<usize>().is_ok())
        && fields
            .get(2)
            .is_some_and(|range| value[range.clone()].trim_start().starts_with('{'))
}

fn parse_1c_localized_strings(value: &str) -> Result<Vec<LocalizedString>> {
    let value = value.trim();
    let fields = scan_braced_fields(value, 0)?;
    if fields
        .first()
        .is_some_and(|range| value[range.clone()].trim() == "0")
    {
        return Ok(Vec::new());
    }
    let first = fields
        .first()
        .ok_or_else(|| anyhow!("localized value is empty"))?;
    let first_value = value[first.clone()].trim();
    if first_value != "1" {
        let count = first_value.parse::<usize>()?;
        return parse_1c_flat_localized_strings(value, &fields, count);
    }
    if fields
        .get(1)
        .is_some_and(|range| value[range.clone()].trim().parse::<usize>().is_ok())
        && fields
            .get(2)
            .is_some_and(|range| value[range.clone()].trim_start().starts_with('{'))
    {
        let count = value[fields[1].clone()].trim().parse::<usize>()?;
        parse_1c_nested_localized_strings(value, &fields, count)
    } else {
        parse_1c_flat_localized_strings(value, &fields, 1)
    }
}

fn parse_1c_flat_localized_strings(
    value: &str,
    fields: &[Range<usize>],
    count: usize,
) -> Result<Vec<LocalizedString>> {
    if fields.len() != 1 + count * 2 {
        return Err(anyhow!("flat localized value field count mismatch"));
    }
    let mut output = Vec::with_capacity(count);
    let mut index = 1usize;
    for _ in 0..count {
        let lang = parse_1c_quoted_string(&value[fields[index].clone()])?;
        let content = parse_1c_quoted_string(&value[fields[index + 1].clone()])?;
        output.push(LocalizedString { lang, content });
        index += 2;
    }
    Ok(output)
}

fn parse_1c_nested_localized_strings(
    value: &str,
    fields: &[Range<usize>],
    count: usize,
) -> Result<Vec<LocalizedString>> {
    if fields.len() != 2 + count {
        return Err(anyhow!("nested localized value field count mismatch"));
    }
    let mut output = Vec::with_capacity(count);
    for range in fields.iter().skip(2) {
        let pair = scan_braced_fields(value, range.start)?;
        if pair.len() != 2 {
            return Err(anyhow!("nested localized pair field count mismatch"));
        }
        let lang = parse_1c_quoted_string(&value[pair[0].clone()])?;
        let content = parse_1c_quoted_string(&value[pair[1].clone()])?;
        output.push(LocalizedString { lang, content });
    }
    Ok(output)
}

fn one_c_values_equal_ignoring_ws(left: &str, right: &str) -> bool {
    compact_1c_value(left) == compact_1c_value(right)
}

fn compact_1c_value(value: &str) -> String {
    let mut output = String::with_capacity(value.len());
    let mut chars = value.chars().peekable();
    let mut in_string = false;
    while let Some(ch) = chars.next() {
        if ch == '"' {
            output.push(ch);
            if in_string && chars.peek() == Some(&'"') {
                output.push(chars.next().unwrap());
            } else {
                in_string = !in_string;
            }
            continue;
        }
        if !in_string && ch.is_ascii_whitespace() {
            continue;
        }
        output.push(ch);
    }
    output
}

fn append_form_body_command(
    text: &mut String,
    command: &FormXmlCommand,
    command_uuids: &BTreeMap<String, String>,
    source: Option<&MetadataSourceContext>,
) -> Result<bool> {
    let fields = scan_braced_fields(text, 0)?;
    if fields.first().map(|range| text[range.clone()].trim()) != Some("0") {
        return Ok(false);
    }
    let Some(count_range) = fields.get(1).cloned() else {
        return Ok(false);
    };
    let Ok(count) = text[count_range.clone()].trim().parse::<usize>() else {
        return Ok(false);
    };
    if fields.len() != 2 + count {
        return Ok(false);
    }
    let Some(uuid) = command_uuids.get(&command.name) else {
        return Ok(false);
    };
    let entry = format_form_body_new_command(command, uuid, source)?;
    text.replace_range(count_range, &(count + 1).to_string());
    let insert_at = text
        .rfind('}')
        .ok_or_else(|| anyhow!("Form commands section is not closed"))?;
    text.insert_str(insert_at, &format!(",{entry}"));
    Ok(true)
}

fn format_form_body_new_command(
    command: &FormXmlCommand,
    uuid: &str,
    source: Option<&MetadataSourceContext>,
) -> Result<String> {
    let action = command.action.as_deref().unwrap_or("");
    let current_row_use = command
        .current_row_use
        .map(form_command_current_row_use_code)
        .unwrap_or("0");
    let modifies_saved_data = if command.modifies_saved_data == Some(true) {
        "1"
    } else {
        "0"
    };
    let functional_options = if command.functional_options.is_empty() {
        "{0,0}".to_string()
    } else if let Some(source) = source {
        format_form_reference_list(source, &command.functional_options)?
    } else {
        "{0,0}".to_string()
    };

    Ok(format!(
        "{{11,{{{},{}}},{},{},{},0,0,0,{},{},{},0,{}}}",
        command.id,
        uuid,
        format_1c_string(&command.name),
        format_1c_synonyms(&command.title),
        format_1c_synonyms(&command.tooltip),
        format_1c_string(action),
        current_row_use,
        modifies_saved_data,
        functional_options
    ))
}

fn form_command_current_row_use_code(value: FormXmlCommandCurrentRowUse) -> &'static str {
    match value {
        FormXmlCommandCurrentRowUse::DontUse => "3",
    }
}

fn format_form_reference_list(
    source: &MetadataSourceContext,
    references: &[String],
) -> Result<String> {
    let mut text = format!("{{0,{}", references.len());
    for reference in references {
        let uuid = source.resolve_metadata_reference_uuid(reference)?;
        text.push(',');
        text.push_str(&uuid);
    }
    text.push('}');
    Ok(text)
}

fn replace_braced_field(text: &mut String, index: usize, value: &str) -> Result<()> {
    let fields = scan_braced_fields(text, 0)?;
    let range = fields
        .get(index)
        .ok_or_else(|| anyhow!("Form layout has no field {index}"))?
        .clone();
    text.replace_range(range, value);
    Ok(())
}

pub fn parse_form_body_blob(blob: &[u8]) -> Result<ParsedFormBodyBlob> {
    let inflated = inflate_raw(blob).context("failed to inflate Form body blob")?;
    let plain = String::from_utf8(inflated).context("Form body blob is not valid UTF-8")?;
    let container = FormBodyContainer::parse(&plain)?;
    let layout = plain[container.layout_range.clone()].trim().to_string();
    let module_text = parse_1c_quoted_string(plain[container.module_range.clone()].trim())
        .context("Form body module text field is not a quoted string")?;
    Ok(ParsedFormBodyBlob {
        layout,
        module_text,
        trailing: container
            .trailing_ranges
            .into_iter()
            .map(|range| plain[range].trim().to_string())
            .collect(),
        trailing_fields: container.trailing_fields,
    })
}

#[derive(Debug, Clone)]
struct FormBodyContainer {
    layout_range: Range<usize>,
    module_range: Range<usize>,
    trailing_ranges: Vec<Range<usize>>,
    trailing_fields: usize,
}

impl FormBodyContainer {
    fn parse(plain: &str) -> Result<Self> {
        let body_start = plain
            .find('{')
            .ok_or_else(|| anyhow!("Form body has no braced payload"))?;
        let fields = scan_braced_fields(plain, body_start)?;
        if fields.first().map(|range| plain[range.clone()].trim()) != Some("4") {
            return Err(anyhow!("Form body does not start with type marker 4"));
        }
        let layout_range = fields
            .get(1)
            .ok_or_else(|| anyhow!("Form body has no layout field"))?
            .clone();
        validate_form_body_layout(plain[layout_range.clone()].trim())?;
        let module_range = fields
            .get(2)
            .ok_or_else(|| anyhow!("Form body has no module text field"))?
            .clone();
        if parse_1c_quoted_string(plain[module_range.clone()].trim()).is_err() {
            return Err(anyhow!(
                "Form body module text field is not a quoted string"
            ));
        }
        Ok(Self {
            layout_range,
            module_range,
            trailing_ranges: fields.iter().skip(3).cloned().collect(),
            trailing_fields: fields.len().saturating_sub(3),
        })
    }
}

fn validate_form_body_layout(layout: &str) -> Result<()> {
    let fields = scan_braced_fields(layout, 0)?;
    if !fields.first().is_some_and(|range| {
        layout[range.clone()]
            .trim()
            .chars()
            .all(|ch| ch.is_ascii_digit())
    }) {
        return Err(anyhow!(
            "Form body layout field does not start with a numeric marker"
        ));
    }
    Ok(())
}

pub fn pack_role_rights_blob_from_xml(
    base_blob: &[u8],
    xml: &[u8],
) -> Result<PackedRawDeflatedBlob> {
    let rights = parse_role_rights_xml(xml)?;
    let inflated = inflate_raw(base_blob).context("failed to inflate base Role rights blob")?;
    let mut plain =
        String::from_utf8(inflated).context("base Role rights blob is not valid UTF-8")?;
    let body_start = plain
        .find('{')
        .ok_or_else(|| anyhow!("base Role rights body has no braced payload"))?;
    let fields = scan_braced_fields(&plain, body_start)?;
    if fields.first().map(|range| plain[range.clone()].trim()) != Some("10") {
        return Err(anyhow!(
            "base Role rights body does not start with type marker 10"
        ));
    }
    let objects_range = fields
        .get(1)
        .ok_or_else(|| anyhow!("base Role rights body has no object rights field"))?
        .clone();
    let templates_range = fields
        .get(2)
        .ok_or_else(|| anyhow!("base Role rights body has no restriction templates field"))?
        .clone();
    let set_for_new_objects_range = fields
        .get(3)
        .ok_or_else(|| anyhow!("base Role rights body has no setForNewObjects field"))?
        .clone();
    let mut replacements = role_right_value_replacements(&plain, objects_range, &rights.objects)?;
    replacements.extend(role_restriction_template_value_replacements(
        &plain,
        templates_range,
        &rights.restriction_templates,
    )?);
    replacements.push((
        set_for_new_objects_range,
        if rights.set_for_new_objects { "1" } else { "0" }.to_string(),
    ));
    if let Some(value) = rights.set_for_attributes_by_default
        && let Some(range) = fields.get(4)
    {
        replacements.push((range.clone(), if value { "1" } else { "0" }.to_string()));
    }
    if let Some(value) = rights.independent_rights_of_child_objects
        && let Some(range) = fields.get(5)
    {
        replacements.push((range.clone(), if value { "1" } else { "0" }.to_string()));
    }
    replacements.sort_by(|left, right| right.0.start.cmp(&left.0.start));
    for (range, replacement) in replacements {
        plain.replace_range(range, &replacement);
    }
    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

pub fn role_rights_base_free_blockers(xml: &[u8]) -> Result<Vec<String>> {
    let rights = parse_role_rights_xml(xml)?;
    let conditional_rights = rights
        .objects
        .iter()
        .flat_map(|object| object.rights.iter())
        .filter(|right| right.restriction_by_condition.is_some())
        .count();
    let enabled_rights = rights
        .objects
        .iter()
        .flat_map(|object| object.rights.iter())
        .filter(|right| right.value)
        .count();
    let total_rights = rights
        .objects
        .iter()
        .map(|object| object.rights.len())
        .sum::<usize>();
    let mut blockers = Vec::new();
    blockers.push(format!(
        "source XML has {} object entries but does not carry the base Role object table order or per-object entry identifiers",
        rights.objects.len()
    ));
    blockers.push(format!(
        "source XML has {total_rights} explicit rights ({enabled_rights} enabled) by name, while the Config row stores platform right UUID slots whose order and complete disabled-right set are read from the base blob"
    ));
    if conditional_rights > 0 {
        blockers.push(format!(
            "source XML has {conditional_rights} conditional rights, but the base blob owns the restricted-right payload shape and condition slot mapping"
        ));
    }
    if !rights.restriction_templates.is_empty() {
        blockers.push(format!(
            "source XML has {} restriction templates, but staging currently patches the existing base template table instead of generating its full serialized shape",
            rights.restriction_templates.len()
        ));
    }
    if rights.set_for_attributes_by_default.is_some()
        || rights.independent_rights_of_child_objects.is_some()
    {
        blockers.push(
            "source XML may set optional role flags, but their presence and trailing field positions are preserved from the base blob".to_string(),
        );
    }
    Ok(blockers)
}

pub fn pack_command_interface_blob_from_xml(
    base_blob: &[u8],
    xml: &[u8],
) -> Result<PackedRawDeflatedBlob> {
    let entries = parse_command_interface_xml(xml)?;
    if base_blob.is_empty() {
        return pack_command_interface_entries_without_base(&entries);
    }
    let inflated =
        inflate_raw(base_blob).context("failed to inflate base CommandInterface blob")?;
    let mut plain =
        String::from_utf8(inflated).context("base CommandInterface blob is not valid UTF-8")?;
    let body_start = plain
        .find('{')
        .ok_or_else(|| anyhow!("base CommandInterface body has no braced payload"))?;
    let fields = scan_braced_fields(&plain, body_start)?;
    if fields.first().map(|range| plain[range.clone()].trim()) != Some("7") {
        return Err(anyhow!(
            "base CommandInterface body does not start with type marker 7"
        ));
    }
    let count_range = fields
        .get(2)
        .ok_or_else(|| anyhow!("base CommandInterface body has no command count"))?;
    let count = plain[count_range.clone()]
        .trim()
        .parse::<usize>()
        .context("invalid base CommandInterface command count")?;
    if count != entries.len() {
        return Err(anyhow!(
            "CommandInterface.xml command count {} does not match base blob command count {}",
            entries.len(),
            count
        ));
    }
    let required_fields = 3 + count * 2;
    if fields.len() < required_fields {
        return Err(anyhow!(
            "base CommandInterface body has {} fields, expected at least {}",
            fields.len(),
            required_fields
        ));
    }

    let mut replacements = Vec::with_capacity(count);
    for (index, entry) in entries.iter().enumerate() {
        let common_range = fields[3 + index * 2 + 1].clone();
        let common = if entry.common { "1" } else { "0" };
        replacements.push((common_range, format!("{{0,{{0,{{\"B\",{common}}},0}}}}")));
    }
    replacements.sort_by(|left, right| right.0.start.cmp(&left.0.start));
    for (range, replacement) in replacements {
        replace_1c_value_if_different(&mut plain, range, &replacement);
    }
    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

pub fn command_interface_xml_can_pack_without_base(xml: &[u8]) -> Result<bool> {
    let entries = parse_command_interface_xml(xml)?;
    Ok(entries
        .iter()
        .all(|entry| format_raw_command_interface_ref(&entry.name).is_ok()))
}

pub fn command_interface_base_free_blockers(xml: &[u8]) -> Result<Vec<String>> {
    let entries = parse_command_interface_xml(xml)?;
    let raw_count = entries
        .iter()
        .filter(|entry| format_raw_command_interface_ref(&entry.name).is_ok())
        .count();
    let readable = entries
        .iter()
        .filter(|entry| format_raw_command_interface_ref(&entry.name).is_err())
        .map(|entry| entry.name.as_str())
        .collect::<Vec<_>>();
    if readable.is_empty() {
        return Ok(Vec::new());
    }

    let readable_count = readable.len();
    let sample = readable
        .iter()
        .take(3)
        .copied()
        .collect::<Vec<_>>()
        .join(", ");
    let mut blockers = Vec::new();
    blockers.push(format!(
        "source XML has {} command visibility entries ({readable_count} readable refs, {raw_count} raw kind:uuid refs), but base-free packing can only synthesize raw numeric kind:uuid command tuples",
        entries.len()
    ));
    blockers.push(format!(
        "readable CommandInterface refs such as {sample} require the active base row to preserve the platform command tuple kind, UUID and serialized command order"
    ));
    blockers.push(
        "staging currently patches visibility flags into the existing CommandInterface row and validates the command count against the base blob".to_string(),
    );
    Ok(blockers)
}

fn pack_command_interface_entries_without_base(
    entries: &[CommandInterfaceXmlEntry],
) -> Result<PackedRawDeflatedBlob> {
    let mut fields = Vec::with_capacity(3 + entries.len() * 2 + 5);
    fields.push("7".to_string());
    fields.push("1".to_string());
    fields.push(entries.len().to_string());
    for entry in entries {
        fields.push(format_raw_command_interface_ref(&entry.name)?);
        let common = if entry.common { "1" } else { "0" };
        fields.push(format!("{{0,{{0,{{\"B\",{common}}},0}}}}"));
    }
    fields.extend(["0", "0", "0", "0", "0"].into_iter().map(String::from));
    let plain = format!("{{{}}}", fields.join(","));
    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

fn format_raw_command_interface_ref(name: &str) -> Result<String> {
    let (kind, uuid) = name
        .split_once(':')
        .ok_or_else(|| anyhow!("base-free CommandInterface command must be kind:uuid: {name}"))?;
    let kind = kind.trim();
    let uuid = uuid.trim();
    if kind.is_empty()
        || !kind.chars().all(|ch| ch.is_ascii_digit())
        || uuid::Uuid::parse_str(uuid).is_err()
    {
        return Err(anyhow!(
            "base-free CommandInterface command must be numeric kind and UUID: {name}"
        ));
    }
    Ok(format!("{{{kind},{uuid}}}"))
}

pub fn pack_exchange_plan_content_blob_from_xml(
    base_blob: &[u8],
    xml: &[u8],
    source: &MetadataSourceContext,
) -> Result<PackedRawDeflatedBlob> {
    let items = parse_exchange_plan_content_xml(xml)?;
    if !base_blob.is_empty() {
        let inflated =
            inflate_raw(base_blob).context("failed to inflate base ExchangePlanContent blob")?;
        let plain = String::from_utf8(inflated)
            .context("base ExchangePlanContent blob is not valid UTF-8")?;
        let body_start = plain
            .find('{')
            .ok_or_else(|| anyhow!("base ExchangePlanContent body has no braced payload"))?;
        let fields = scan_braced_fields(&plain, body_start)?;
        if fields.first().map(|range| plain[range.clone()].trim()) != Some("2") {
            return Err(anyhow!(
                "base ExchangePlanContent body does not start with type marker 2"
            ));
        }
    }

    let mut plain = format!("{{2,{}", items.len());
    for item in items {
        let uuid = source
            .resolve_metadata_reference_uuid(&item.metadata)
            .with_context(|| format!("failed to resolve ExchangePlanContent {}", item.metadata))?;
        let auto_record = if item.auto_record { "1" } else { "0" };
        plain.push(',');
        plain.push_str(&uuid);
        plain.push(',');
        plain.push_str(auto_record);
    }
    plain.push('}');

    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

pub fn pack_predefined_data_blob_from_xml(
    base_blob: &[u8],
    xml: &[u8],
) -> Result<PackedRawDeflatedBlob> {
    let items = parse_predefined_data_xml(xml)?;
    let by_id = flatten_predefined_xml_items(&items)?;
    let inflated = inflate_raw(base_blob).context("failed to inflate base PredefinedData blob")?;
    let mut plain =
        String::from_utf8(inflated).context("base PredefinedData blob is not valid UTF-8")?;
    let body_start = plain
        .find('{')
        .ok_or_else(|| anyhow!("base PredefinedData body has no braced payload"))?;
    let fields = scan_braced_fields(&plain, body_start)?;
    if !matches!(
        fields.first().map(|range| plain[range.clone()].trim()),
        Some("0" | "1")
    ) {
        return Err(anyhow!(
            "base PredefinedData body does not start with type marker 0 or 1"
        ));
    }
    let table_range = fields
        .get(1)
        .ok_or_else(|| anyhow!("base PredefinedData body has no table field"))?
        .clone();
    let mut replacements = Vec::<(Range<usize>, String)>::new();
    let mut seen = BTreeSet::<String>::new();
    collect_predefined_replacements(&plain, table_range, &by_id, &mut seen, &mut replacements)?;
    let missing = by_id
        .keys()
        .filter(|id| !seen.contains(*id))
        .cloned()
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(anyhow!(
            "PredefinedData XML contains items missing in base blob: {}",
            missing.join(", ")
        ));
    }

    replacements.sort_by(|left, right| right.0.start.cmp(&left.0.start));
    for (range, replacement) in replacements {
        plain.replace_range(range, &replacement);
    }
    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

pub fn predefined_data_base_free_blockers(xml: &[u8]) -> Result<Vec<String>> {
    let items = parse_predefined_data_xml(xml)?;
    let flat = flatten_predefined_xml_items(&items)?;
    let folders = flat.values().filter(|item| item.is_folder).count();
    let child_links = flat.len().saturating_sub(items.len());
    let folder_word = if folders == 1 { "folder" } else { "folders" };
    let child_link_word = if child_links == 1 {
        "nested child link"
    } else {
        "nested child links"
    };
    Ok(vec![
        format!(
            "source XML has {} predefined items ({folders} {folder_word}, {child_links} {child_link_word}) addressed by UUID, but the Config row owns the serialized predefined table order and parent/children rowset shape",
            flat.len()
        ),
        "source XML carries editable item values only; staging currently patches existing base rows and fails for source items missing from the base blob".to_string(),
        "base PredefinedData row preserves type UUID slots, parent reference slots, value count, and trailing fields that are not fully represented in Predefined.xml".to_string(),
    ])
}

pub fn pack_business_process_flowchart_blob_from_xml(
    base_blob: &[u8],
    xml: &[u8],
) -> Result<PackedRawDeflatedBlob> {
    let items = parse_flowchart_xml(xml)?;
    let by_id = items
        .into_iter()
        .map(|item| (item.id.clone(), item))
        .collect::<BTreeMap<_, _>>();
    let inflated =
        inflate_raw(base_blob).context("failed to inflate base BusinessProcess Flowchart blob")?;
    let mut plain = String::from_utf8(inflated)
        .context("base BusinessProcess Flowchart blob is not valid UTF-8")?;
    let body_start = plain
        .find('{')
        .ok_or_else(|| anyhow!("base BusinessProcess Flowchart body has no braced payload"))?;
    let fields = scan_braced_fields(&plain, body_start)?;
    if fields.first().map(|range| plain[range.clone()].trim()) != Some("5") {
        return Err(anyhow!(
            "base BusinessProcess Flowchart body does not start with type marker 5"
        ));
    }
    let item_count = plain[fields
        .get(2)
        .ok_or_else(|| anyhow!("base BusinessProcess Flowchart has no item count"))?
        .clone()]
    .trim()
    .parse::<usize>()
    .context("invalid BusinessProcess Flowchart item count")?;
    let mut replacements = Vec::<(Range<usize>, String)>::new();
    let mut seen = BTreeSet::<String>::new();
    let mut index = 3usize;
    for _ in 0..item_count {
        let code_range = fields
            .get(index)
            .ok_or_else(|| anyhow!("base BusinessProcess Flowchart item has no code"))?
            .clone();
        let code = plain[code_range].trim().to_string();
        let body_range = fields
            .get(index + 1)
            .ok_or_else(|| anyhow!("base BusinessProcess Flowchart item has no body"))?
            .clone();
        collect_flowchart_item_replacements(
            &plain,
            &code,
            body_range,
            &by_id,
            &mut seen,
            &mut replacements,
        )?;
        index += 2;
    }
    let missing = by_id
        .keys()
        .filter(|id| !seen.contains(*id))
        .cloned()
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(anyhow!(
            "Flowchart.xml contains items missing in base blob: {}",
            missing.join(", ")
        ));
    }

    replacements.sort_by(|left, right| right.0.start.cmp(&left.0.start));
    for (range, replacement) in replacements {
        plain.replace_range(range, &replacement);
    }
    let blob = deflate_raw(plain.as_bytes())?;
    let output_sha256 = hex_sha256(&blob);
    Ok(PackedRawDeflatedBlob {
        blob,
        plain_bytes: plain.len(),
        output_sha256,
    })
}

pub fn business_process_flowchart_base_free_blockers(xml: &[u8]) -> Result<Vec<String>> {
    let items = parse_flowchart_xml(xml)?;
    let mut kind_counts = BTreeMap::<String, usize>::new();
    let mut event_count = 0usize;
    let mut explanation_count = 0usize;
    let mut task_description_count = 0usize;
    for item in &items {
        *kind_counts.entry(item.kind.clone()).or_default() += 1;
        event_count += item.events.len();
        if item.explanation.is_some() {
            explanation_count += 1;
        }
        if item.task_description.is_some() {
            task_description_count += 1;
        }
    }
    let kind_summary = if kind_counts.is_empty() {
        "none".to_string()
    } else {
        kind_counts
            .iter()
            .map(|(kind, count)| format!("{kind}={count}"))
            .collect::<Vec<_>>()
            .join(", ")
    };
    let mut blockers = Vec::new();
    blockers.push(format!(
        "source XML has {} flowchart items ({kind_summary}) addressed by id/name, but the Config row owns the serialized item table order and per-item type code slots",
        items.len()
    ));
    blockers.push(
        "source XML carries editable values only; staging currently patches the existing base item payloads to preserve platform-owned geometry, connector, and nested field shapes"
            .to_string(),
    );
    if event_count > 0 {
        blockers.push(format!(
            "source XML has {event_count} event handlers, but handler positions are selected from the base event slot table for each flowchart item type"
        ));
    }
    if explanation_count > 0 || task_description_count > 0 {
        blockers.push(format!(
            "source XML has {explanation_count} explanations and {task_description_count} task descriptions, but their serialized field positions are preserved from the base blob"
        ));
    }
    Ok(blockers)
}

fn role_right_value_replacements(
    plain: &str,
    objects_range: Range<usize>,
    objects: &[RoleObjectRightsXml],
) -> Result<Vec<(Range<usize>, String)>> {
    let object_fields = scan_braced_fields(plain, objects_range.start)?;
    let base_count_range = object_fields
        .first()
        .ok_or_else(|| anyhow!("base Role object rights field is empty"))?
        .clone();
    let base_count = plain[base_count_range]
        .trim()
        .parse::<usize>()
        .context("invalid base Role object rights count")?;
    if base_count != objects.len() {
        return Err(anyhow!(
            "Role Rights.xml object count {} does not match base blob object count {}",
            objects.len(),
            base_count
        ));
    }
    if object_fields.len() != base_count + 1 {
        return Err(anyhow!(
            "base Role object rights field count {} does not match declared count {}",
            object_fields.len().saturating_sub(1),
            base_count
        ));
    }

    let mut base_entries = Vec::with_capacity(base_count);
    for object_index in 0..base_count {
        let entry_range = object_fields[object_index + 1].clone();
        let entry_fields = scan_braced_fields(plain, entry_range.start)?;
        let object_ref_range = entry_fields.get(0).ok_or_else(|| {
            anyhow!("base Role object rights entry {object_index} has no object reference")
        })?;
        validate_role_object_ref(plain, object_ref_range.clone())
            .with_context(|| format!("base Role object rights entry {object_index}"))?;
        let rights_range = entry_fields.get(1).ok_or_else(|| {
            anyhow!("base Role object rights entry {object_index} has no rights payload")
        })?;
        base_entries.push(rights_range.clone());
    }

    let mut replacements = Vec::new();
    for (object_index, rights_range) in base_entries.into_iter().enumerate() {
        let object = objects.get(object_index).ok_or_else(|| {
            anyhow!("Role Rights.xml has no object for base entry {object_index}")
        })?;
        replacements.extend(role_object_right_value_replacements(
            plain,
            rights_range,
            object,
        )?);
    }
    Ok(replacements)
}

fn validate_role_object_ref(plain: &str, object_ref_range: Range<usize>) -> Result<()> {
    let fields = scan_braced_fields(plain, object_ref_range.start)?;
    let uuid_range = fields
        .get(1)
        .ok_or_else(|| anyhow!("object reference has no UUID field"))?;
    let uuid = plain[uuid_range.clone()].trim();
    if !is_uuid_text(uuid) {
        return Err(anyhow!("object reference has invalid UUID {uuid}"));
    }
    Ok(())
}

fn role_restriction_template_value_replacements(
    plain: &str,
    templates_range: Range<usize>,
    templates: &[RoleRestrictionTemplateXml],
) -> Result<Vec<(Range<usize>, String)>> {
    let fields = scan_braced_fields(plain, templates_range.start)?;
    let base_count_range = fields
        .first()
        .ok_or_else(|| anyhow!("base Role restriction templates field is empty"))?
        .clone();
    let base_count = plain[base_count_range]
        .trim()
        .parse::<usize>()
        .context("invalid base Role restriction templates count")?;
    if base_count != templates.len() {
        return Err(anyhow!(
            "Role Rights.xml restriction template count {} does not match base blob count {}",
            templates.len(),
            base_count
        ));
    }
    if fields.len() != base_count + 1 {
        return Err(anyhow!(
            "base Role restriction templates field count {} does not match declared count {}",
            fields.len().saturating_sub(1),
            base_count
        ));
    }

    let mut replacements = Vec::with_capacity(base_count * 2);
    for (template_index, template) in templates.iter().enumerate() {
        let entry_range = fields[template_index + 1].clone();
        let entry_fields = scan_braced_fields(plain, entry_range.start)?;
        if entry_fields.len() != 2 {
            return Err(anyhow!(
                "base Role restriction template entry {template_index} has {} fields, expected 2",
                entry_fields.len()
            ));
        }
        parse_1c_quoted_string(plain[entry_fields[0].clone()].trim()).with_context(|| {
            format!("base Role restriction template entry {template_index} has invalid name")
        })?;
        parse_1c_quoted_string(plain[entry_fields[1].clone()].trim()).with_context(|| {
            format!("base Role restriction template entry {template_index} has invalid condition")
        })?;
        replacements.push((entry_fields[0].clone(), format_1c_string(&template.name)));
        replacements.push((
            entry_fields[1].clone(),
            format_1c_string(&template.condition),
        ));
    }
    Ok(replacements)
}

fn role_object_right_value_replacements(
    plain: &str,
    rights_range: Range<usize>,
    object: &RoleObjectRightsXml,
) -> Result<Vec<(Range<usize>, String)>> {
    let fields = scan_braced_fields(plain, rights_range.start)?;
    let marker = fields
        .first()
        .map(|range| plain[range.clone()].trim())
        .ok_or_else(|| anyhow!("base Role rights payload is empty"))?;
    let (start, count) = match marker {
        "0" => (1usize, (fields.len().saturating_sub(1)) / 2),
        "1" => {
            let count_range = fields
                .get(1)
                .ok_or_else(|| anyhow!("base Role restricted rights payload has no count"))?;
            let count = plain[count_range.clone()]
                .trim()
                .parse::<usize>()
                .context("invalid base Role restricted rights count")?;
            (2usize, count)
        }
        _ => return Err(anyhow!("unsupported base Role rights marker {marker}")),
    };
    let required_fields = start + count * 2;
    if fields.len() < required_fields {
        return Err(anyhow!(
            "base Role rights payload has {} fields, expected at least {}",
            fields.len(),
            required_fields
        ));
    }
    let rights_by_name = object
        .rights
        .iter()
        .map(|right| (right.name.as_str(), right))
        .collect::<BTreeMap<_, _>>();
    let mut restrictions_by_uuid = BTreeMap::<String, RoleRightRestrictionXml>::new();
    let mut replacements = Vec::with_capacity(count);
    for right_index in 0..count {
        let uuid = plain[fields[start + right_index * 2].clone()].trim();
        let name = role_right_name(uuid)
            .ok_or_else(|| anyhow!("unsupported base Role right UUID {uuid}"))?;
        let right = rights_by_name.get(name).copied();
        let value_range = fields[start + right_index * 2 + 1].clone();
        replacements.push((
            value_range,
            if right.is_some_and(|right| right.value) {
                "1"
            } else {
                "-1"
            }
            .to_string(),
        ));
        if let Some(restriction) = right.and_then(|right| right.restriction_by_condition.as_ref()) {
            restrictions_by_uuid.insert(uuid.to_string(), restriction.clone());
        }
    }
    if marker == "1" && !restrictions_by_uuid.is_empty() {
        let restrictions_count_range = fields
            .get(required_fields)
            .ok_or_else(|| {
                anyhow!("base Role restricted rights payload has no restrictions count")
            })?
            .clone();
        let restrictions_count = plain[restrictions_count_range]
            .trim()
            .parse::<usize>()
            .context("invalid base Role restrictions count")?;
        if restrictions_count > 0 {
            replacements.extend(role_restriction_condition_replacements(
                plain,
                restrictions_count,
                &fields[required_fields + 1..],
                &restrictions_by_uuid,
            )?);
        }
    }
    Ok(replacements)
}

fn role_restriction_condition_replacements(
    plain: &str,
    count: usize,
    ranges: &[Range<usize>],
    restrictions_by_uuid: &BTreeMap<String, RoleRightRestrictionXml>,
) -> Result<Vec<(Range<usize>, String)>> {
    let mut replacements = Vec::new();
    if ranges.len() == count {
        for range in ranges {
            collect_role_restriction_entry_replacement(
                plain,
                range.clone(),
                restrictions_by_uuid,
                &mut replacements,
            )?;
        }
        return Ok(replacements);
    }
    if ranges.len() != 1 {
        return Ok(replacements);
    }

    let nested = scan_braced_fields(plain, ranges[0].start)?;
    if nested.len() == count * 2
        && nested
            .first()
            .is_some_and(|range| is_uuid_text(plain[range.clone()].trim()))
    {
        for pair in nested.chunks(2) {
            collect_role_restriction_pair_replacement(
                plain,
                pair[0].clone(),
                pair[1].clone(),
                restrictions_by_uuid,
                &mut replacements,
            )?;
        }
        return Ok(replacements);
    }
    if nested.len() == count {
        for range in nested {
            collect_role_restriction_entry_replacement(
                plain,
                range,
                restrictions_by_uuid,
                &mut replacements,
            )?;
        }
    }
    Ok(replacements)
}

fn collect_role_restriction_entry_replacement(
    plain: &str,
    entry_range: Range<usize>,
    restrictions_by_uuid: &BTreeMap<String, RoleRightRestrictionXml>,
    replacements: &mut Vec<(Range<usize>, String)>,
) -> Result<()> {
    let fields = scan_braced_fields(plain, entry_range.start)?;
    if fields.len() != 2 {
        return Ok(());
    }
    collect_role_restriction_pair_replacement(
        plain,
        fields[0].clone(),
        fields[1].clone(),
        restrictions_by_uuid,
        replacements,
    )
}

fn collect_role_restriction_pair_replacement(
    plain: &str,
    uuid_range: Range<usize>,
    restriction_range: Range<usize>,
    restrictions_by_uuid: &BTreeMap<String, RoleRightRestrictionXml>,
    replacements: &mut Vec<(Range<usize>, String)>,
) -> Result<()> {
    let uuid = plain[uuid_range].trim();
    let Some(restriction) = restrictions_by_uuid.get(uuid) else {
        return Ok(());
    };
    if let Some(ranges) = role_restriction_condition_ranges(plain, restriction_range)? {
        replacements.push((ranges.condition, format_1c_string(&restriction.condition)));
        if let (Some(field), Some(field_range)) = (&restriction.field, ranges.field) {
            replacements.push((field_range, format_1c_string(field)));
        }
    }
    Ok(())
}

struct RoleRestrictionConditionRanges {
    condition: Range<usize>,
    field: Option<Range<usize>>,
}

fn role_restriction_condition_ranges(
    plain: &str,
    restriction_range: Range<usize>,
) -> Result<Option<RoleRestrictionConditionRanges>> {
    let wrapper = scan_braced_fields(plain, restriction_range.start)?;
    let marker = wrapper.first().map(|range| plain[range.clone()].trim());
    let body_range = match marker {
        Some("1") => wrapper.get(1),
        Some("2") => wrapper.get(2),
        _ => return Ok(None),
    };
    let Some(body_range) = body_range else {
        return Ok(None);
    };
    let body = scan_braced_fields(plain, body_range.start)?;
    if body.first().map(|range| plain[range.clone()].trim()) != Some("1") {
        return Ok(None);
    }
    let Some(condition_range) = body.get(1) else {
        return Ok(None);
    };
    parse_1c_quoted_string(plain[condition_range.clone()].trim())?;
    let field = if marker == Some("2") {
        body.get(3)
            .map(|range| role_restriction_field_text_range(plain, range.clone()))
            .transpose()?
            .flatten()
    } else {
        None
    };
    Ok(Some(RoleRestrictionConditionRanges {
        condition: condition_range.clone(),
        field,
    }))
}

fn role_restriction_field_text_range(
    plain: &str,
    field_range: Range<usize>,
) -> Result<Option<Range<usize>>> {
    if parse_1c_quoted_string(plain[field_range.clone()].trim()).is_ok() {
        return Ok(Some(field_range));
    }
    if plain.as_bytes().get(field_range.start) != Some(&b'{') {
        return Ok(None);
    }
    let fields = scan_braced_fields(plain, field_range.start)?;
    if fields.first().map(|range| plain[range.clone()].trim()) == Some("1")
        && let Some(value_range) = fields.get(1)
        && parse_1c_quoted_string(plain[value_range.clone()].trim()).is_ok()
    {
        return Ok(Some(value_range.clone()));
    }
    for range in fields {
        if plain.as_bytes().get(range.start) == Some(&b'{')
            && let Some(nested) = role_restriction_field_text_range(plain, range)?
        {
            return Ok(Some(nested));
        }
    }
    Ok(None)
}

fn role_right_name(uuid: &str) -> Option<&'static str> {
    ROLE_RIGHT_NAMES
        .iter()
        .find_map(|(right_uuid, name)| (*right_uuid == uuid).then_some(*name))
}

